############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "contextFiniteSolutionSets.pl", "contextForm.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("FiniteSolutionSets"); Context()->variables->are(q => 'Real'); $answer = Formula("{27/14}");
############################################################ # Body ############################################################
BEGIN_PGML Solve the equation [`q - \frac{3}{7} = \frac{3}{2}`] for [`q\text{.}`]
[_]{$answer}{10}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION To remove the [`\frac{3}{7}`] from the left side, we need to _add_ [`\frac{3}{7}`] to each side of the equation.
[```\newcommand{\highlight}[1]{\mathchoice{\colorbox{lightsapphire}{$\displaystyle #1$}}{\colorbox{lightsapphire}{$\textstyle #1$}}{\colorbox{lightsapphire}{$\scriptstyle #1$}}{\colorbox{lightsapphire}{$\scriptscriptstyle #1$}}}\newcommand{\addright}[1]{{\highlight{{{}+#1}}}}\newcommand{\amp}{&} \begin{aligned} q-\frac{3}{7}\amp=\frac{3}{2}\\ q-\frac{3}{7}\addright{\frac{3}{7}}\amp=\frac{3}{2}\addright{\frac{3}{7}}\\ q\amp=\highlight{\frac{21}{14}}+\highlight{\frac{6}{14}}\\ q\amp=\frac{27}{14} \end{aligned} ```]
We should check the solution by substituting [`\frac{27}{14}`] in for [`q`] in the original equation:
[```\newcommand{\substitute}[1]{{\color{blue}{{#1}}}}\newcommand{\confirm}[1]{\stackrel{\checkmark}{#1}}\newcommand{\wonder}[1]{\stackrel{\text{?}}{#1}}\newcommand{\amp}{&} \begin{aligned} q-\frac{3}{7}\amp=\frac{3}{2}\\ \substitute{\frac{27}{14}}-\frac{3}{7}\amp\wonder{=}\frac{3}{2}\\ \frac{27}{14}-\frac{6}{14}\amp\wonder{=}\frac{3}{2}\\ \frac{21}{14}\amp\wonder{=}\frac{3}{2}\\ \frac{3}{2}\amp\confirm{=}\frac{3}{2} \end{aligned} ```]
The solution [`\frac{27}{14}`] is checked, and the solution set is [`\left\{\frac{27}{14}\right\}\text{.}`]
END_PGML_SOLUTION
